	Azure.login();
	return JSON.stringify(Azure.getMetricsData());
}
catch (error) {
	error += (String(error).endsWith('.')) ? '' : '.';
	Zabbix.log(3, '[ Azure SQL instance ] ERROR: ' + error);
	return JSON.stringify({ 'error': error });
}
